code.C++:
#include <stdio.h>

int main() {
    int number;
    scanf("%d", &number);

    // Check if the number is even or odd
    if (number % 2 == 0) {
        printf("Even\n");
    } else {
        printf("Odd\n");
    }

    return 0;
}

